        format!(
            "jjb:{}:{}{}:n: ",
            hallmark,
            JJRF_FIREMARK_PREFIX,
            firemark.jjrf_as_str(),
        )
    } else {
        eprintln!("jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
        return 1;
    };

